// Processamento de Relato Urbano
const input = $input.first().json.body;
const report = input.report;
const description = (report.description || '').toLowerCase();

// Classificação por palavras-chave
let priority = 'normal';
let category = report.category;
let tags = [];

// Detecção de urgência
const urgentKeywords = ['urgente', 'perigo', 'risco', 'acidente', 'vazamento', 'desabamento', 'incêndio'];
const highKeywords = ['buraco', 'cratera', 'alagamento', 'queda', 'sem luz', 'falta água'];

if (urgentKeywords.some(k => description.includes(k))) {
  priority = 'urgente';
  tags.push('ATENÇÃO_IMEDIATA');
} else if (highKeywords.some(k => description.includes(k))) {
  priority = 'alta';
}

// Categorização automática
const categoryMap = {
  'buraco': 'infraestrutura',
  'iluminação': 'iluminacao_publica',
  'lixo': 'limpeza_urbana',
  'esgoto': 'saneamento',
  'árvore': 'meio_ambiente',
  'calçada': 'acessibilidade',
  'sinal': 'sinalizacao'
};

for (const [keyword, cat] of Object.entries(categoryMap)) {
  if (description.includes(keyword)) {
    category = cat;
    tags.push(`AUTO_${cat.toUpperCase()}`);
    break;
  }
}

// Análise de severidade
let severity = report.severity || 'media';
if (priority === 'urgente') severity = 'critica';
else if (priority === 'alta') severity = 'alta';

// Enriquecimento com dados contextuais
const enrichedData = {
  bairro_normalizado: report.location_address?.split(',')[1]?.trim() || null,
  coordenadas_validas: !!(report.latitude && report.longitude),
  tem_fotos: (report.photos?.length || 0) > 0,
  hora_criacao: new Date(report.created_at).getHours(),
  dia_semana: new Date(report.created_at).toLocaleDateString('pt-BR', { weekday: 'long' })
};

return {
  report_id: report.id,
  report_type: 'urban',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    validated_category: category,
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Processamento de Relato de Transporte
const input = $input.first().json.body;
const report = input.report;
const description = (report.description || '').toLowerCase();

let priority = 'normal';
let tags = [];

// Detecção de problemas críticos de transporte
const criticalKeywords = ['acidente', 'atropelamento', 'colisão', 'quebrado', 'parado'];
const highKeywords = ['lotado', 'atraso', 'não passou', 'cancelado', 'sem ar'];

if (criticalKeywords.some(k => description.includes(k))) {
  priority = 'urgente';
  tags.push('INCIDENTE_CRITICO');
} else if (highKeywords.some(k => description.includes(k))) {
  priority = 'alta';
  tags.push('PROBLEMA_OPERACIONAL');
}

// Classificação por tipo de problema
const problemTypes = {
  'atraso': 'ATRASO',
  'lotado': 'SUPERLOTACAO',
  'ar condicionado': 'CLIMATIZACAO',
  'limpeza': 'HIGIENE',
  'motorista': 'CONDUTA',
  'acessibilidade': 'ACESSIBILIDADE',
  'segurança': 'SEGURANCA'
};

for (const [keyword, tag] of Object.entries(problemTypes)) {
  if (description.includes(keyword)) {
    tags.push(tag);
  }
}

// Análise temporal
const hora = parseInt(report.occurrence_time?.split(':')[0] || '12');
if (hora >= 6 && hora <= 9) tags.push('HORARIO_PICO_MANHA');
else if (hora >= 17 && hora <= 20) tags.push('HORARIO_PICO_TARDE');

const enrichedData = {
  linha_codigo: report.line_code_custom || null,
  horario_ocorrencia: report.occurrence_time,
  data_ocorrencia: report.occurrence_date,
  horario_pico: hora >= 6 && hora <= 9 || hora >= 17 && hora <= 20
};

return {
  report_id: report.id,
  report_type: 'transport',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    validated_category: report.report_type,
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Processamento de Avaliação de Serviço
const input = $input.first().json.body;
const report = input.report;

let priority = 'normal';
let tags = [];

// Análise de sentimento baseada em rating
const rating = report.rating_stars || 3;
if (rating <= 2) {
  priority = 'alta';
  tags.push('AVALIACAO_NEGATIVA');
} else if (rating >= 4) {
  tags.push('AVALIACAO_POSITIVA');
}

// Análise do texto da avaliação
const text = (report.rating_text || '').toLowerCase();
const negativeKeywords = ['péssimo', 'horrível', 'demora', 'descaso', 'falta', 'nunca'];
const positiveKeywords = ['excelente', 'ótimo', 'rápido', 'atencioso', 'eficiente'];

if (negativeKeywords.some(k => text.includes(k))) {
  priority = 'alta';
  tags.push('FEEDBACK_CRITICO');
}
if (positiveKeywords.some(k => text.includes(k))) {
  tags.push('FEEDBACK_ELOGIO');
}

const enrichedData = {
  servico_id: report.service_id,
  rating_numerico: rating,
  tem_comentario: !!report.rating_text,
  sentimento_detectado: rating <= 2 ? 'negativo' : rating >= 4 ? 'positivo' : 'neutro'
};

return {
  report_id: report.id,
  report_type: 'service_rating',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    validated_category: 'avaliacao_servico',
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Log de sucesso
const response = $input.first().json;
console.log('Callback enviado com sucesso:', response);
return { success: true, response };
